String _d(List<int> encoded) {
  const mask = [0xF1, 0x3A, 0xC7, 0x82, 0x5E, 0xD9, 0x44, 0xAB];
  return utf8.decode([
    for (var i = 0; i < encoded.length; i++)
      encoded[i] ^ mask[i % mask.length],
  ]);
}

